// Generated by AI Assistant

import common, { ApplicationId } from '@eclipse-che/common';
import { DEVWORKSPACE_RESTORE_ATTRIBUTES } from '@eclipse-che/common';
import { dump } from 'js-yaml';

import * as DwApi from '@/services/backend-client/devWorkspaceApi';
import { fetchResources } from '@/services/backend-client/devworkspaceResourcesApi';
import * as DwtApi from '@/services/backend-client/devWorkspaceTemplateApi';
import devfileApi from '@/services/devfileApi';
import { DEVWORKSPACE_CHE_EDITOR } from '@/services/devfileApi/devWorkspace/metadata';
import { loadResourcesContent } from '@/services/registry/resources';
import {
  COMPONENT_UPDATE_POLICY,
  REGISTRY_URL,
} from '@/services/workspace-client/devworkspace/devWorkspaceClient';
import { AppThunk } from '@/store';
import { selectApplications } from '@/store/ClusterInfo';
import { getEditor } from '@/store/DevfileRegistries/getEditor';
import { verifyAuthorized } from '@/store/SanityCheck';
import {
  selectDefaultComponents,
  selectOpenVSXUrl,
  selectPluginRegistryInternalUrl,
  selectPluginRegistryUrl,
} from '@/store/ServerConfig';
import { getDevWorkspaceClient } from '@/store/Workspaces/devWorkspaces/actions/actionCreators/helpers';
import {
  devWorkspacesAddAction,
  devWorkspacesErrorAction,
  devWorkspacesRequestAction,
} from '@/store/Workspaces/devWorkspaces/actions/actions';

export const restoreWorkspaceFromBackup =
  (
    namespace: string,
    workspaceName: string,
    backupImageUrl: string,
    editorId: string,
    memoryLimit?: number,
    cpuLimit?: number,
  ): AppThunk =>
  async (dispatch, getState) => {
    const state = getState();
    const openVSXUrl = selectOpenVSXUrl(state);
    const pluginRegistryUrl = selectPluginRegistryUrl(state);
    const pluginRegistryInternalUrl = selectPluginRegistryInternalUrl(state);
    const defaultComponents = selectDefaultComponents(state);
    const clusterConsole = selectApplications(state).find(
      app => app.id === ApplicationId.CLUSTER_CONSOLE,
    );

    try {
      await verifyAuthorized(dispatch, getState);

      dispatch(devWorkspacesRequestAction());

      // Fetch editor devfile content from the plugin registry
      const editorResponse = await getEditor(editorId, dispatch, getState);
      if (!editorResponse.content) {
        throw new Error(editorResponse.error ?? `Failed to fetch editor '${editorId}'`);
      }
      const { content: editorContent, editorYamlUrl } = editorResponse;

      // Build the restore devfile with default components. The devworkspace-generator
      // merges this with the editor content to produce a DevWorkspace + DevWorkspaceTemplate
      // pair with proper spec.contributions linking the two.
      //
      // Including default components (from CHE_DEFAULT_SPEC_DEVENVIRONMENTS_DEFAULTCOMPONENTS)
      // ensures the restored workspace has a dev container, matching the workspace creation
      // flow. Resource limits are applied to this container's devfile definition, so the
      // generator places them correctly — no post-generation heuristics needed.
      const components = JSON.parse(JSON.stringify(defaultComponents));
      if (components.length > 0 && components[0].container) {
        if (memoryLimit !== undefined && memoryLimit > 0) {
          const memoryLimitGi = Math.round(memoryLimit / (1024 * 1024 * 1024));
          components[0].container.memoryLimit = `${memoryLimitGi}Gi`;
        }
        if (cpuLimit !== undefined && cpuLimit > 0) {
          components[0].container.cpuLimit = cpuLimit.toString();
        }
      }

      const restoreDevfile: Record<string, unknown> = {
        schemaVersion: '2.2.0',
        metadata: {
          name: workspaceName,
        },
        attributes: {
          [DEVWORKSPACE_RESTORE_ATTRIBUTES.RESTORE_WORKSPACE]: 'true',
          [DEVWORKSPACE_RESTORE_ATTRIBUTES.RESTORE_SOURCE_IMAGE]: backupImageUrl,
        },
      };
      if (components.length > 0) {
        restoreDevfile.components = components;
      }

      const resourcesContent = await fetchResources({
        devfileContent: dump(restoreDevfile),
        editorPath: undefined,
        editorContent,
      });

      const resources = loadResourcesContent(resourcesContent);

      const devWorkspaceResource = resources.find(
        (r): r is devfileApi.DevWorkspace => r.kind === 'DevWorkspace',
      );
      if (!devWorkspaceResource) {
        throw new Error('Failed to find DevWorkspace in fetched resources.');
      }

      const devWorkspaceTemplateResource = resources.find(
        (r): r is devfileApi.DevWorkspaceTemplate => r.kind === 'DevWorkspaceTemplate',
      );
      if (!devWorkspaceTemplateResource) {
        throw new Error('Failed to find DevWorkspaceTemplate in fetched resources.');
      }

      // Ensure the workspace name matches user input (generator may produce a different name)
      devWorkspaceResource.metadata.name = workspaceName;
      devWorkspaceResource.metadata.namespace = namespace;

      if (!devWorkspaceResource.metadata.annotations) {
        devWorkspaceResource.metadata.annotations = {};
      }
      devWorkspaceResource.metadata.annotations[DEVWORKSPACE_CHE_EDITOR] = editorId;

      // Inject env vars (plugin registry URL, dashboard URL, openVSX URL) into editor containers
      getDevWorkspaceClient().addEnvVarsToContainers(
        devWorkspaceTemplateResource.spec?.components,
        pluginRegistryUrl,
        pluginRegistryInternalUrl,
        openVSXUrl,
        clusterConsole,
      );

      // Tell Che Code to open the restored .code-workspace file so the
      // project folder is loaded automatically on startup.
      for (const component of devWorkspaceTemplateResource.spec?.components ?? []) {
        if (component.container) {
          const env = component.container.env ?? [];
          env.push({ name: 'VSCODE_DEFAULT_WORKSPACE', value: '/projects/.code-workspace' });
          component.container.env = env;
        }
      }

      if (!devWorkspaceTemplateResource.metadata.annotations) {
        devWorkspaceTemplateResource.metadata.annotations = {};
      }
      if (editorYamlUrl) {
        devWorkspaceTemplateResource.metadata.annotations[COMPONENT_UPDATE_POLICY] = 'managed';
        devWorkspaceTemplateResource.metadata.annotations[REGISTRY_URL] = editorYamlUrl;
      }
      devWorkspaceTemplateResource.metadata.namespace = namespace;

      // Create with started=false so the IDE loader's CheckRunningWorkspacesLimit step
      // enforces maxNumberOfRunningWorkspacesPerUser before starting the workspace.
      devWorkspaceResource.spec.started = false;

      // Create the DevWorkspaceTemplate first, then set ownerReference once we have the DW uid
      const createdTemplate = await DwtApi.createTemplate(devWorkspaceTemplateResource);

      // Create the DevWorkspace — spec.contributions from fetchResources already references the template
      const { devWorkspace: createdWorkspace } = await DwApi.createWorkspace(devWorkspaceResource);

      // Set ownerReference on the template for automatic cleanup
      await DwtApi.patchTemplate(namespace, createdTemplate.metadata.name, [
        {
          op: 'add',
          path: '/metadata/ownerReferences',
          value: [
            {
              apiVersion: 'workspace.devfile.io/v1alpha2',
              kind: 'DevWorkspace',
              name: createdWorkspace.metadata.name,
              uid: createdWorkspace.metadata.uid,
            },
          ],
        },
      ]);

      dispatch(devWorkspacesAddAction(createdWorkspace));
    } catch (e) {
      const errorMessage =
        'Failed to restore workspace, reason: ' + common.helpers.errors.getMessage(e);
      dispatch(devWorkspacesErrorAction(errorMessage));
      throw e;
    }
  };
